body:
Switch case default branch initializes to x when it should initialise to register data_q.

 Code line  below

```
 data_d = data_q;
```

will produce x to procmux input A

```
assign data_d = \$procmux$5 (1'bx, 2'b01, { \$procmux$7_CMP , \$procmux$6_CMP  });
```

but if data_d will get it's default value from input "we" instead of reg data_q it works.

```
//        data_d = we; This works.
```

```
  assign data_d = \$procmux$5 (we, 2'b01, { \$procmux$7_CMP , \$procmux$6_CMP  });
```

Used script

```
design -reset
read_verilog u_test.v 
hierarchy -top u_test 
proc; opt; memory; dff2dffe; wreduce; clean; opt
write_verilog -norename y_u_bug.v 
```

X initialisation code

```
module u_test (we, wad, rad, clk, rst);

    input    [3:0] wad;
    input    we;
    output   [3:0] rad;
    input    clk;
    input    rst;

    wire [3:0]  rad;
    reg  [3:0]  r_q;
    wire [3:0]  r_d;
    reg  data_d, data_q;

    assign rad = r_q;

    always @(posedge clk) begin
        if (rst) begin
            data_q <= 1;
         r_q        <= 0;
        end
        else begin
           data_q <= data_d;
        r_q        <= r_d;
        end
    end

    always @(*) begin

        data_d = data_q;
//        data_d = we; This works.

        case ( { we, we } )
            2'b10 :
                begin
                    data_d = 1'b0;
                end
            2'b01 : 
                begin
                    data_d = 1'b1;
                end
            default:;
        endcase

    end

    assign r_d = data_q ? wad : r_q;

endmodule

```

